proof_block:
let pt = self_.get_pagetable_by_pcid(pcid).unwrap();
let map = pt.mapping_4k();
let dom_has_va = map.dom().contains(va);

// Pull both ensures conjuncts into context using modern `is Some` syntax to
// avoid the deprecated `is_Some()` triggers. The shared anchor `dom_has_va`
// connects `r1 is Some` and `r2 is Some`.
assert(dom_has_va == (r1 is Some));
assert(dom_has_va == (r2 is Some));
assert((r1 is Some) == (r2 is Some));

// Case-split on whether the address is mapped.
if r1 is Some {
    // Both runs are Some.
    assert(r2 is Some);
    let e1 = r1->Some_0;
    let e2 = r2->Some_0;

    // Both page entries map to the same MapEntry at va.
    assert(map[va] == page_entry_to_map_entry(&e1));
    assert(map[va] == page_entry_to_map_entry(&e2));
    assert(page_entry_to_map_entry(&e1) == page_entry_to_map_entry(&e2));

    // Use the functional-uniqueness lemma to derive the field-level equalities
    // pinned by spec_page_entry_to_map_entry: addr, perm.write,
    // perm.execute_disable.
    lemma_page_entry_to_map_entry_inj(e1, e2);
    assert(e1.addr == e2.addr);
    assert(e1.perm.write == e2.perm.write);
    assert(e1.perm.execute_disable == e2.perm.execute_disable);

    // Re-affirm the page_entry_to_map_entry equality with explicit triggers so
    // z3 can line up the two-run conjuncts when discharging the postcondition.
    assert forall|p: PageEntry|
        #![trigger page_entry_to_map_entry(&p)]
        page_entry_to_map_entry(&p)
            == spec_page_entry_to_map_entry(&p) by {
    };
} else {
    // Both runs are None; det_eq's implication is vacuously true.
    assert(r1 is None);
    assert(r2 is None);
}

helper_lemmas:
proof fn lemma_page_entry_to_map_entry_inj(p1: PageEntry, p2: PageEntry)
    requires
        page_entry_to_map_entry(&p1) == page_entry_to_map_entry(&p2),
    ensures
        p1.addr == p2.addr,
        p1.perm.write == p2.perm.write,
        p1.perm.execute_disable == p2.perm.execute_disable,
{
    let m1 = spec_page_entry_to_map_entry(&p1);
    let m2 = spec_page_entry_to_map_entry(&p2);
    assert(m1 == m2);
    assert(m1.addr == m2.addr);
    assert(m1.write == m2.write);
    assert(m1.execute_disable == m2.execute_disable);
}
